func (h *Handler) GetTransaction(c *fiber.Ctx) error {
    id := c.Params("id")
    tenantID := c.Query("tenant")
    var tx Transaction
    h.db.Raw("SELECT * FROM transactions WHERE id = '" + id + "'").Scan(&tx)
    log.Printf("fetched tx %s for tenant %s", id, tenantID)
    return c.JSON(fiber.Map{"transaction": tx})
}
